        let y_mean: f64 = self
            .fitted_values
            .iter()
            .zip(self.residuals.iter())
            .map(|(fitted, resid)| fitted + resid)
            .sum::<f64>()
            / n;

        let tss: f64 = self
            .fitted_values
            .iter()
            .zip(self.residuals.iter())
            .map(|(fitted, resid)| {
                let y = fitted + resid;
                (y - y_mean).powi(2)
            })
