use criterion::{black_box, criterion_group, criterion_main, BenchmarkId, Criterion};
use ndarray::{Array1, Array2};
use stats_models::{Lm, Fit};
use resample::{bootstrap, BootstrapConfig, BootstrapStatistic};

/// Bootstrap statistic that computes linear model coefficients
struct LmBootstrapStat {
    n_params: usize,
}

impl BootstrapStatistic for LmBootstrapStat {
    fn compute(&self, x: ndarray::ArrayView2<f64>, y: ndarray::ArrayView1<f64>) -> Array1<f64> {
        match Lm::fit_ndarray(x, y) {
            Ok(fit) => Array1::from(fit.coefficients().to_vec()),
            Err(_) => Array1::zeros(self.n_params),
        }
    }

    fn n_stats(&self) -> usize {
        self.n_params
    }
}

fn generate_regression_data(n_obs: usize) -> (Array2<f64>, Array1<f64>) {
    let mut x_data = Vec::with_capacity(n_obs * 2);
    let mut y_data = Vec::with_capacity(n_obs);

    use rand::{SeedableRng, Rng};
    let mut rng = rand::rngs::StdRng::seed_from_u64(42);

    for i in 0..n_obs {
        // Design matrix with intercept and one predictor
        x_data.push(1.0); // intercept
        let x_val = i as f64 / n_obs as f64 * 10.0; // x ranges from 0 to 10
        x_data.push(x_val);

        // y = 1 + 2*x + noise
        let noise = rng.gen::<f64>() - 0.5; // noise in [-0.5, 0.5]
        y_data.push(1.0 + 2.0 * x_val + noise);
    }

    let x_matrix = Array2::from_shape_vec((n_obs, 2), x_data).unwrap();
    let y_vector = Array1::from(y_data);

    (x_matrix, y_vector)
}

fn benchmark_bootstrap_varying_samples(c: &mut Criterion) {
    let mut group = c.benchmark_group("bootstrap_n_samples");

    // Fixed dataset size, vary bootstrap samples
    let n_obs = 100;
    let (x, y) = generate_regression_data(n_obs);
    let stat = LmBootstrapStat { n_params: 2 };

    for n_samples in &[100, 500, 1000, 5000] {
        group.bench_with_input(
            BenchmarkId::new("parallel", n_samples),
            n_samples,
            |b, &n| {
                let config = BootstrapConfig {
                    n_samples: n,
                    seed: Some(42),
                    parallel: true,
                };
                b.iter(|| {
                    let _result = bootstrap(
                        black_box(x.view()),
                        black_box(y.view()),
                        black_box(&stat),
                        black_box(Some(config.clone())),
                    );
                })
            },
        );

        group.bench_with_input(
            BenchmarkId::new("sequential", n_samples),
            n_samples,
            |b, &n| {
                let config = BootstrapConfig {
                    n_samples: n,
                    seed: Some(42),
                    parallel: false,
                };
                b.iter(|| {
                    let _result = bootstrap(
                        black_box(x.view()),
                        black_box(y.view()),
                        black_box(&stat),
                        black_box(Some(config.clone())),
                    );
                })
            },
        );
    }

    group.finish();
}

fn benchmark_bootstrap_varying_dataset_size(c: &mut Criterion) {
    let mut group = c.benchmark_group("bootstrap_data_size");

    // Fixed bootstrap samples, vary dataset size
    let n_samples = 1000;
    let stat = LmBootstrapStat { n_params: 2 };

    for n_obs in &[50, 100, 500, 1000] {
        let (x, y) = generate_regression_data(*n_obs);

        group.bench_with_input(
            BenchmarkId::new("parallel", n_obs),
            n_obs,
            |b, _| {
                let config = BootstrapConfig {
                    n_samples,
                    seed: Some(42),
                    parallel: true,
                };
                b.iter(|| {
                    let _result = bootstrap(
                        black_box(x.view()),
                        black_box(y.view()),
                        black_box(&stat),
                        black_box(Some(config.clone())),
                    );
                })
            },
        );
    }

    group.finish();
}

fn benchmark_bootstrap_integrated_fit(c: &mut Criterion) {
    let mut group = c.benchmark_group("bootstrap_integrated");

    // Benchmark the integrated bootstrap method on fitted models
    let n_obs = 100;
    let (x, y) = generate_regression_data(n_obs);

    // First fit the model
    let fit = Lm::fit_ndarray(x.view(), y.view()).unwrap();

    for n_samples in &[100, 500, 1000] {
        group.bench_with_input(
            BenchmarkId::new("lm_bootstrap", n_samples),
            n_samples,
            |b, &n| {
                b.iter(|| {
                    let _result = fit.bootstrap(black_box(n));
                })
            },
        );
    }

    group.finish();
}

criterion_group!(
    benches,
    benchmark_bootstrap_varying_samples,
    benchmark_bootstrap_varying_dataset_size,
    benchmark_bootstrap_integrated_fit
);
criterion_main!(benches);

