//! High-performance resampling methods for statistical inference
//!
//! This crate provides parallel implementations of bootstrap, jackknife,
//! and other resampling techniques optimized for large datasets.

#![forbid(unsafe_code)]
#![warn(missing_docs)]

use ndarray::{Array1, Array2, ArrayView1, ArrayView2, Axis};
use rand::{thread_rng, Rng, SeedableRng};
use rayon::prelude::*;
use std::sync::Arc;

/// Resampling errors
#[derive(thiserror::Error, Debug)]
pub enum ResampleError {
    /// Invalid sample size
    #[error("Invalid sample size: {0}")]
    InvalidSampleSize(usize),
    /// Insufficient data
    #[error("Insufficient data: need at least {0} observations")]
    InsufficientData(usize),
}

/// Configuration for bootstrap resampling
#[derive(Debug, Clone)]
pub struct BootstrapConfig {
    /// Number of bootstrap samples
    pub n_samples: usize,
    /// Random seed for reproducibility
    pub seed: Option<u64>,
    /// Whether to use parallel processing
    pub parallel: bool,
}

impl Default for BootstrapConfig {
    fn default() -> Self {
        Self {
            n_samples: 1000,
            seed: None,
            parallel: true,
        }
    }
}

/// Bootstrap result containing statistics from all resamples
#[derive(Debug)]
pub struct BootstrapResult {
    /// Bootstrap statistics for each sample
    pub statistics: Array2<f64>,
    /// Bootstrap estimates (mean of statistics)
    pub estimates: Array1<f64>,
    /// Standard errors (std of statistics)
    pub std_errors: Array1<f64>,
    /// Confidence intervals (if computed)
    pub confidence_intervals: Option<Array2<f64>>,
}

/// Trait for statistics that can be computed on resampled data
pub trait BootstrapStatistic {
    /// Compute the statistic for given data
    fn compute(&self, x: ArrayView2<f64>, y: ArrayView1<f64>) -> Array1<f64>;

    /// Number of statistics this function returns
    fn n_stats(&self) -> usize;
}

/// Perform bootstrap resampling with parallel processing
///
/// This function implements case resampling (resampling rows of the data matrix)
/// with optional parallelization for performance on large datasets.
///
/// # Arguments
/// * `x` - Predictor matrix (n_observations × n_predictors)
/// * `y` - Response vector (n_observations)
/// * `statistic` - Function to compute statistics on resampled data
/// * `config` - Bootstrap configuration
///
/// # Returns
/// * `BootstrapResult` containing bootstrap distribution and estimates
pub fn bootstrap<S>(
    x: ArrayView2<f64>,
    y: ArrayView1<f64>,
    statistic: S,
    config: Option<BootstrapConfig>,
) -> Result<BootstrapResult, ResampleError>
where
    S: BootstrapStatistic + Sync + Send,
{
    let config = config.unwrap_or_default();
    let n_obs = x.nrows();
    let n_stats = statistic.n_stats();

    if n_obs == 0 {
        return Err(ResampleError::InsufficientData(1));
    }

    if config.n_samples == 0 {
        return Err(ResampleError::InvalidSampleSize(config.n_samples));
    }

    // Set random seed if provided
    if let Some(seed) = config.seed {
        // Note: We'll handle seeding in the parallel case differently
        let _ = seed;
    }

    let statistic = Arc::new(statistic);

    // Parallel bootstrap sampling
    let bootstrap_stats: Vec<Array1<f64>> = if config.parallel {
        (0..config.n_samples)
            .into_par_iter()
            .map(|_| {
                let mut rng = thread_rng();
                let indices: Vec<usize> = (0..n_obs).map(|_| rng.gen_range(0..n_obs)).collect();

                // Create bootstrap sample
                let x_boot = x.select(Axis(0), &indices);
                let y_boot = y.select(Axis(0), &indices);

                // Compute statistic
                statistic.compute(x_boot.view(), y_boot.view())
            })
            .collect()
    } else {
        // Sequential version for reproducible results with seed
        let mut rng = if let Some(seed) = config.seed {
            rand::rngs::StdRng::seed_from_u64(seed)
        } else {
            rand::rngs::StdRng::from_entropy()
        };

        (0..config.n_samples)
            .map(|_| {
                let indices: Vec<usize> = (0..n_obs).map(|_| rng.gen_range(0..n_obs)).collect();

                // Create bootstrap sample
                let x_boot = x.select(Axis(0), &indices);
                let y_boot = y.select(Axis(0), &indices);

                // Compute statistic
                statistic.compute(x_boot.view(), y_boot.view())
            })
            .collect()
    };

    // Combine results into matrix
    let mut statistics = Array2::zeros((config.n_samples, n_stats));
    for (i, stat) in bootstrap_stats.iter().enumerate() {
        statistics.row_mut(i).assign(stat);
    }

    // Compute estimates and standard errors
    let estimates = statistics.mean_axis(Axis(0)).unwrap();
    let std_errors = statistics.std_axis(Axis(0), 0.0);

    Ok(BootstrapResult {
        statistics,
        estimates,
        std_errors,
        confidence_intervals: None,
    })
}

/// Compute confidence intervals from bootstrap distribution
pub fn bootstrap_confidence_intervals(
    result: &mut BootstrapResult,
    alpha: f64,
) -> Result<(), ResampleError> {
    let _confidence_level = 1.0 - alpha;
    let lower_percentile = alpha / 2.0;
    let upper_percentile = 1.0 - alpha / 2.0;

    let n_stats = result.statistics.ncols();
    let mut intervals = Array2::zeros((n_stats, 2));

    for j in 0..n_stats {
        let mut values: Vec<f64> = result.statistics.column(j).to_vec();
        values.sort_by(|a, b| a.partial_cmp(b).unwrap());

        let n = values.len();
        let lower_idx = ((n as f64) * lower_percentile).floor() as usize;
        let upper_idx = ((n as f64) * upper_percentile).ceil() as usize - 1;

        intervals[[j, 0]] = values[lower_idx.min(n - 1)];
        intervals[[j, 1]] = values[upper_idx.min(n - 1)];
    }

    result.confidence_intervals = Some(intervals);
    Ok(())
}

/// Jackknife resampling (leave-one-out)
///
/// Computes the jackknife estimate by systematically leaving out one observation
/// at a time and computing the statistic on the remaining data.
pub fn jackknife<S>(
    x: ArrayView2<f64>,
    y: ArrayView1<f64>,
    statistic: S,
) -> Result<BootstrapResult, ResampleError>
where
    S: BootstrapStatistic + Sync + Send,
{
    let n_obs = x.nrows();
    let n_stats = statistic.n_stats();

    if n_obs <= 1 {
        return Err(ResampleError::InsufficientData(2));
    }

    let statistic = Arc::new(statistic);

    // Parallel jackknife computation
    let jackknife_stats: Vec<Array1<f64>> = (0..n_obs)
        .into_par_iter()
        .map(|i| {
            // Create indices excluding observation i
            let indices: Vec<usize> = (0..n_obs).filter(|&idx| idx != i).collect();

            // Create jackknife sample
            let x_jack = x.select(Axis(0), &indices);
            let y_jack = y.select(Axis(0), &indices);

            // Compute statistic
            statistic.compute(x_jack.view(), y_jack.view())
        })
        .collect();

    // Combine results into matrix
    let mut statistics = Array2::zeros((n_obs, n_stats));
    for (i, stat) in jackknife_stats.iter().enumerate() {
        statistics.row_mut(i).assign(stat);
    }

    // Compute jackknife estimates and standard errors
    let estimates = statistics.mean_axis(Axis(0)).unwrap();

    // Jackknife standard error formula: sqrt((n-1)/n * sum((theta_i - theta_bar)^2))
    let n = n_obs as f64;
    let variance = statistics.map_axis(Axis(0), |column| {
        let mean = column.mean().unwrap();
        let sum_sq_diff: f64 = column.iter().map(|&x| (x - mean).powi(2)).sum();
        ((n - 1.0) / n) * sum_sq_diff
    });
    let std_errors = variance.mapv(f64::sqrt);

    Ok(BootstrapResult {
        statistics,
        estimates,
        std_errors,
        confidence_intervals: None,
    })
}

