mod tests {
    use super::*;
    use ndarray::Array2;

    /// Simple statistic for testing: just return the mean of y
    struct MeanStatistic;

    impl BootstrapStatistic for MeanStatistic {
        fn compute(&self, _x: ArrayView2<f64>, y: ArrayView1<f64>) -> Array1<f64> {
            Array1::from(vec![y.mean().unwrap_or(0.0)])
        }

