/// * `BootstrapResult` containing bootstrap distribution and estimates
pub fn bootstrap<S>(
    x: ArrayView2<f64>,
    y: ArrayView1<f64>,
    statistic: S,
    config: Option<BootstrapConfig>,
) -> Result<BootstrapResult, ResampleError>
where
    S: BootstrapStatistic + Sync + Send,
{
    let config = config.unwrap_or_default();
    let n_obs = x.nrows();
    let n_stats = statistic.n_stats();

    if n_obs == 0 {
        return Err(ResampleError::InsufficientData(1));
    }

    if config.n_samples == 0 {
        return Err(ResampleError::InvalidSampleSize(config.n_samples));
    }

    // Set random seed if provided
    if let Some(seed) = config.seed {
        // Note: We'll handle seeding in the parallel case differently
        let _ = seed;
    }

    let statistic = Arc::new(statistic);

    // Parallel bootstrap sampling
    let bootstrap_stats: Vec<Array1<f64>> = if config.parallel {
        (0..config.n_samples)
            .into_par_iter()
            .map(|_| {
                let mut rng = thread_rng();
                let indices: Vec<usize> = (0..n_obs).map(|_| rng.gen_range(0..n_obs)).collect();

                // Create bootstrap sample
                let x_boot = x.select(Axis(0), &indices);

