        let mut seeder = SipRng::from_seed(config.seed.unwrap_or_else(|| rand::thread_rng().gen()).to_le_bytes());
        (0..config.n_samples)
            .into_par_iter()
            .map_init(
                || StdRng::from_seed(seeder.gen()),
                |rng, _| {
                    let indices: Vec<usize> = (0..n_obs).map(|_| rng.gen_range(0..n_obs)).collect();

