fn transform_coefficients_back(
    beta_std: &Array1<f64>,
    x_means: &Array1<f64>,
    x_scales: &Array1<f64>,
    y_mean: f64,
) -> (f64, Array1<f64>) { // Returns (intercept, slopes)
    let n_vars = beta_std.len();
    let mut slopes = Array1::zeros(n_vars);

    // Transform slope coefficients
    for j in 0..n_vars {
        slopes[j] = beta_std[j] / x_scales[j];
    }

    // Calculate intercept
    let intercept_adjustment: f64 = (0..n_vars).map(|j| slopes[j] * x_means[j]).sum();
    let intercept = y_mean - intercept_adjustment;

    (intercept, slopes)
